render_strategy.source:
{
  decorators: [Story => <div style={{
    width: "384px"
  }}>
        <Story />
      </div>],
  args: {
    ...defaultArgs,
    title: "Title placeholder, with a maximum line count of three, with automatic truncation"
  },
  render: args => {
    return <Card {...args}>
        <Card.Section>
          <Card.Media>
            <Image src={sanofiImage} alt="Visual representation of Sanofi's healthcare solutions" />
          </Card.Media>
          <Card.Content isCentered={args.isCentered} category="Eyebrow One (i.e Category)" date="Eyebrow Two (i.e Date)" title={<Title variant={args.titleSize}>{args.title}</Title>} subText="Description placeholder, with a maximum line count of five. This
            text will automatically truncate if your content is too long." buttonSlot={<Card.Button aria-label="More actions Card Image Story" icon={IconName.MORE_VERT} onClick={() => notify(args)} />} />
        </Card.Section>
        <Card.Section>
          <Card.Action isCentered={args.isCentered}>
            <LinkStandalone href={sanofiUrl} size={LinkSize.SMALL}>
              Standalone link
            </LinkStandalone>
          </Card.Action>
        </Card.Section>
      </Card>;
  }
}
